    END IF;

    -- Add agent_assigned column if it doesn't exist
    IF NOT EXISTS (
        SELECT 1 FROM information_schema.columns
        WHERE table_name='property_viewings' AND column_name='agent_assigned'
    ) THEN
        ALTER TABLE property_viewings ADD COLUMN agent_assigned VARCHAR(255);
